import{_ as g,y as o,a as r,o as a,ag as c,D as t,g as i}from"./chunks/framework.RVu0gECZ.js";const _=JSON.parse('{"title":"Nhóm khách hàng Giá | Mức giá","description":"","frontmatter":{},"headers":[],"relativePath":"customer/customer-group-price.md","filePath":"customer/customer-group-price.md","lastUpdated":1775325172000}'),m={name:"customer/customer-group-price.md"};function s(p,h,e,u,l,k){const n=o("ImagePopup");return a(),r("div",null,[h[0]||(h[0]=c('<h1 id="nhom-khach-hang-gia-muc-gia" tabindex="-1">Nhóm khách hàng Giá | Mức giá <a class="header-anchor" href="#nhom-khach-hang-gia-muc-gia" aria-label="Permalink to &quot;Nhóm khách hàng Giá | Mức giá&quot;">​</a></h1><p>Định giá theo nhóm khách hàng tại VNS cho phép chủ cửa hàng đưa ra các mức giá sản phẩm khác nhau cho các nhóm khách hàng khác nhau - chẳng hạn như <strong>Thông thường, Bán buôn hoặc Khách</strong>.</p><p>Tính năng này giúp doanh nghiệp tạo chiến lược giá được cá nhân hóa, tặng thưởng cho người mua trung thành và khuyến khích mua số lượng lớn.</p><p>Bằng cách chỉ định khách hàng vào các nhóm cụ thể, bạn có thể kiểm soát số tiền mỗi nhóm trả cho cùng một sản phẩm, giúp mô hình định giá của bạn linh hoạt hơn và tập trung vào khách hàng hơn.</p><h3 id="cac-buoc-tao-nhom-gia-tai-vns" tabindex="-1">Các bước tạo nhóm giá tại VNS <a class="header-anchor" href="#cac-buoc-tao-nhom-gia-tai-vns" aria-label="Permalink to &quot;Các bước tạo nhóm giá tại VNS&quot;">​</a></h3><p><strong>Bước 1</strong>: Đầu tiên, tạo nhóm khách hàng và gán nhóm cho khách hàng hoặc sử dụng các nhóm mặc định như <strong>Chung, Bán buôn hoặc Khách</strong>.</p><p><strong>Bước 2</strong>: Đăng nhập vào bảng quản trị của VNS và vào <strong>Catalog &gt;&gt; Products</strong>.</p><p>Tạo một sản phẩm mới và đi đến trang chỉnh sửa sản phẩm. Bạn sẽ có thể thấy phần <strong>Giá nhóm khách hàng</strong> như trong hình bên dưới.</p>',8)),t(n,{src:"/images/customer/customerPrice.png",alt:"Customer Group Price"}),h[1]||(h[1]=c("<p><strong>Bước 3</strong>: Bây giờ hãy nhấp vào <strong>Thêm mới</strong> và thêm các trường bên dưới:</p><ul><li><p><strong>A) Giá chiết khấu</strong> – Đặt mức chiết khấu phần trăm trên giá sản phẩm.</p></li><li><p><strong>B) Giá cố định</strong> – Đặt giá cố định cho sản phẩm sau khi ưu đãi.</p></li><li><p><strong>C) Số lượng</strong> – Số lượng tối thiểu cần có để được hưởng ưu đãi.</p></li><li><p><strong>D) Nhóm khách hàng</strong> – Chọn nhóm khách hàng (Prime, Guest, Wholesale, General, v.v.).</p></li></ul><p><em>(Lưu ý: Bạn có thể tạo nhóm theo yêu cầu của mình.)</em></p><hr><p><strong>Ví dụ về giá cố định</strong></p><p>Ở đây tôi đã đặt giá cố định cho sản phẩm trong <strong>Nhóm Khách hàng Khách hàng</strong> với số lượng tối thiểu là 1.</p><p>Điều đó có nghĩa là nếu bạn mua một sản phẩm này với giá 2500 USD và Giá nhóm khách hàng được thêm vào là 220 USD thì chi phí sẽ là 220 USD cho số lượng một sản phẩm.</p><p>Vì vậy bây giờ hãy nhấp vào nút <strong>Save</strong> như hình bên dưới.</p>",8)),t(n,{src:"/images/customer/groupPrice.png",alt:"Save Customer Group Price"}),h[2]||(h[2]=i("p",null,"Bây giờ hãy lưu sản phẩm. Bạn có thể thấy sự thay đổi giá theo nhóm.",-1)),h[3]||(h[3]=i("p",null,"Khi đặt cho nhóm Khách có giá cố định, nó sẽ hiển thị giá theo nhóm khách như hình bên dưới.",-1)),t(n,{src:"/images/customer/priceOutput.png",alt:"Group Price Output"}),h[4]||(h[4]=c('<h3 id="athem-nhieu-nhom-khach-hang-đinh-gia" tabindex="-1">AThêm nhiều nhóm khách hàng Định giá <a class="header-anchor" href="#athem-nhieu-nhom-khach-hang-đinh-gia" aria-label="Permalink to &quot;AThêm nhiều nhóm khách hàng Định giá&quot;">​</a></h3><p>Bạn cũng có thể thêm nhiều tùy chọn Giá nhóm khách hàng cho số lượng hoặc nhóm khác nhau để khuyến khích mua số lượng lớn và đưa ra các ưu đãi tốt hơn.</p><p>Ví dụ: bạn có thể định cấu hình cấu trúc định giá theo cấp độ sau:</p><p><strong>Mua 2 cái với giá $400,00 mỗi cái và tiết kiệm 55,56%</strong></p><p><strong>Mua 3 cái với giá $350,00 mỗi cái và tiết kiệm 61,11%</strong></p><p><strong>Mua 4 cái với giá $200,00 mỗi cái và tiết kiệm 77,78%</strong></p><p><strong>Mua 5 cái với giá $150,00 mỗi cái và tiết kiệm 83,33%</strong></p><p>Các mức giá này có thể được thêm trực tiếp vào phần Giá nhóm khách hàng của Bảng quản trị, như hiển thị bên dưới:</p>',8)),t(n,{src:"/images/customer/all-group-price.png",alt:"Multiple Customer Group Pricing"}),h[5]||(h[5]=i("p",null,"Bạn có thể kiểm tra chế độ xem Mặt tiền cửa hàng để xem tất cả các tùy chọn giá của khách hàng theo cấp bậc xuất hiện cùng nhau như thế nào cho cùng một sản phẩm.",-1)),t(n,{src:"/images/customer/priceOutput1.png",alt:"Storefront Multiple Customer Group Pricing"})])}const d=g(m,[["render",s]]);export{_ as __pageData,d as default};
